buggyStarterCode.javascript:
// Define a generic math calculator function
function genericMathCalculator(a, b) {
  // Check if a is an integer
  if (typeof a === 'number' && a % 1 === 0) {
    // Cast a to an integer
    a = Math.floor(a);
  }
  // Check if b is an integer
  if (typeof b === 'number' && b % 1 === 0) {
    // Cast b to an integer
    b = Math.floor(b);
  }
  // Correctly calculate the sum and product of a and b
  return { sum: a + b, product: a * b);
}

